INSERT INTO learning_records (customer_id, mentor_name, coaching_start_date, coaching_end_date, last_coaching_date, contract_months, total_sessions, weekly_sessions, completed_sessions, session_completion_rate, initial_coaching_level, case_interview_progress, case_interview_weaknesses, mentoring_satisfaction, id) VALUES (E'd2c6bd4e-43d8-4aae-92ec-d64c9a3bffc3', E'西村', E'2025-08-07', E'2025-09-07', E'2025-09-29', 1, 6, 1.4, 9, 1.5, E'トップ外資戦略はチャレンジ、その他戦略なら十分内定可能なポテンシャルがある', E'「ロジカルシンキングを超える戦略思考　フェルミ推定の技術」\n「戦略コンサルティングファームの面接試験-case i point」\n「過去問で鍛える地頭力」', E'・馴染みのない業界に対する売上規模推定など応用編のフェルミー問題はまだ時間がかかってしまうこと。\n・フェルミ後のケース問題(売上向上施策など)はまだ自分の中でフレームが身につけられておらず、何を軸で考えていくべきなのか、迷ってしまう。フェルミ推定より、不安定。', E'3', E'9d05fd75-f42a-42fc-8fba-98b7253bced4');
INSERT INTO learning_records (customer_id, completed_sessions, case_interview_progress, case_interview_weaknesses, id) VALUES (E'ff6afa32-c3c5-4d05-885c-890e818be249', 0, E'東大生が書いたケース対策本(書籍)例題全て一周済、DTCケース面接受験、KPMGコンサルケース受験(どちらも不合格)、壁打ち2回(DTCのOB)', E'KPMGからのフィードバックでは資料の読み取りが出来ていないと言われた、DTCでは提示されたお題に対して処理しきれず適切な施策を打てなかった', E'da0c3ad7-e259-4493-a8aa-2e528c913ee8');
INSERT INTO learning_records (customer_id, completed_sessions, initial_coaching_level, case_interview_progress, case_interview_weaknesses, id) VALUES (E'1470bb2b-a8dc-4641-9258-64ca38dbf37d', 0, E'その他戦略はチャレンジ、大手総合なら十分内定可能なポテンシャルがある', E'読んだ書籍：『Case in Point』『現役東大生が書いたフェルミ推定ノート・ケースノート』\n使っている有料サービス：なし\n所属している選抜コミュニティ：なし\n壁打ちの回数など：５～10回\n内定実績：\n　アクセンチュア ビジネスコンサルタント職 内定\n　ベンチャー系コンサル会社 内定', E'ケース面接において特に苦手意識があるのは、言語面での表現に加え、M&Aやpublic sectorに関するケースです。', E'f03a38ee-248d-4271-9dfa-ee641333deb3');
