INSERT INTO learning_records (customer_id, completed_sessions, initial_coaching_level, case_interview_progress, case_interview_weaknesses, id) VALUES (E'994053b4-535c-42d5-9428-0e6bac5f6aea', 0, E'トップ外資戦略はチャレンジ、その他戦略なら十分内定可能なポテンシャルがある', E'東大生フェルミ・ケース\nフェルミ推定から始まる問題解決技術\n現在はMBA同期の戦コン出身者に何回か壁打ちの機会をいただいている', E'お題が出された時に、まず何から考えればいいのか、というところに時間がかかってしまう', E'b3b67923-8896-4173-8c74-2c3bb6fd34bc');
