INSERT INTO learning_records (customer_id, completed_sessions, initial_coaching_level, case_interview_progress, case_interview_weaknesses, id) VALUES (E'03a01399-3375-4458-b6e7-72e3081ba769', 0, E'トップ外資戦略は十分内定可能なポテンシャルがある', E'ADLに内定した際に使用していた書籍「戦略コンサルティングファームの面接試験」を読み返している程度。', E'思考の瞬発力が弱い。基礎的な問題（自動車の市場規模はxxx）といった問題はできるが、応用問題になると思考停止してしまう', E'ca2dbb04-8aed-4681-acde-81b1ecbf1c93');
