INSERT INTO learning_records (customer_id, completed_sessions, initial_coaching_level, case_interview_progress, case_interview_weaknesses, id) VALUES (E'02db3c5a-13a3-4ec2-895f-6677c92b5fee', 0, E'トップ外資戦略はチャレンジ、その他戦略なら十分内定可能なポテンシャルがある', E'壁打ちは20回程度したことがある。', E'ファーストアウトプットでどこまで話せば良いか、また、ノータイムディスカッションの正解がわからない。', E'3e479166-ee43-4921-bb91-a140951b94ac');
INSERT INTO learning_records (customer_id, completed_sessions, id) VALUES (E'0908040a-35be-4a70-850e-1e882699efee', 0, E'43aa6358-7315-4f40-9e63-ff14004b4f14');
INSERT INTO learning_records (customer_id, completed_sessions, initial_coaching_level, case_interview_progress, case_interview_weaknesses, id) VALUES (E'efafa124-8d4c-45ea-ab95-251c0496fce6', 0, E'その他戦略はチャレンジ、大手総合なら十分内定可能なポテンシャルがある', E'big4の選考を一度経験した程度', E'実際のケース面接の中で思考時間が1分だったのだが、どこまで考えればいいかわからず思いつきの施策のみになってしまった。現状分析をフレームワークをたくさん覚えればいいのかそれとも基本的なものだけ押さえてやっていくのかがどれが最適なのかがわからない。ボトルネック特定の客観的な判断の方法がよくわからない。', E'ae502f70-4dfa-4a88-83b5-4833a7d04ca0');
