INSERT INTO learning_records (customer_id, completed_sessions, initial_coaching_level, case_interview_weaknesses, id) VALUES (E'9d7b02c3-867f-436b-8a35-aac2cbfb5f27', 0, E'その他戦略はチャレンジ、大手総合なら十分内定可能なポテンシャルがある', E'始めたてで全てがまっさらというのが正直なところです。あえてあげるとすれば、飲食店の店舗の出店戦略など、身近なケースに関してはイメージがつきやすいですが、自分が携わったことのない事業に関しての問いで止まってしまうことが多いです。', E'4257937e-cdac-4514-8d5e-c6ea2b1ab302');
INSERT INTO learning_records (customer_id, mentor_name, coaching_start_date, coaching_end_date, last_coaching_date, contract_months, total_sessions, weekly_sessions, completed_sessions, session_completion_rate, level_fermi, level_case, level_mck, initial_coaching_level, case_interview_progress, case_interview_weaknesses, mentoring_satisfaction, id) VALUES (E'8b03d62c-1426-41dd-8b9f-7719b7eeb3fe', E'河合', E'2025-10-27', E'2025-12-27', E'2025-11-14', 2, 8, 0.9333333333, 3, 0.375, E'中級者レベル：基本動作を習得しているが、立式、根拠づけ、計算においてミスや指摘を受ける', E'中級者レベル：仮説を元にファーストアウトプットを考える姿勢があるが論理の破綻などの指摘を受ける/ディスカッションに不自然な点がある', E'初級者レベル：MECEに考えられていない、思考がランダム', E'トップ外資戦略はチャレンジ、その他戦略なら十分内定可能なポテンシャルがある', E'以下の本を読みました。壁打ちなどの練習回数は０回です。\n論点思考\n戦略コンサルティング・ファームの面接試験 : 難関突破のための傾向と対策', E'瞬発力がないです。思考のプロセスを教えて欲しいです。', E'5', E'97f7e736-13ff-4f89-bc3c-d5ab88bc5a43');
