INSERT INTO learning_records (customer_id, initial_coaching_level, case_interview_progress, case_interview_weaknesses, id) VALUES (E'351b0194-e8da-4270-aced-7c8da2af386b', E'トップ外資戦略はチャレンジ、その他戦略なら十分内定可能なポテンシャルがある', E'・有料サービス\nMBB内定者の個人メンターの指導を1ヶ月受けていました。\n\n・所属選抜コミュニティ\nNEXVRL, GPAP, オルタナ\n\n・壁打ち回数\n10-20回', E'網羅的な幅出しに苦手感があります。', E'34df844f-7086-4c54-9615-d3e8a70b4e51');
