INSERT INTO learning_records (customer_id, initial_coaching_level, case_interview_weaknesses, id) VALUES (E'50ec307a-3cca-439d-84f3-9da77f4c00f7', E'トップ外資戦略はチャレンジ、その他戦略なら十分内定可能なポテンシャルがある', E'事業戦略に関しては日課でよく接しているが、日本の面接での型板には不慣れ。詳細の部分、または日本特有の注目部分に関しての知識は皆無である可能性がある。\nまた、面接対策自体がまだ初期段階であるため回答に至るまで時間がかかってしまう。', E'c7d2bb79-d204-420b-b0b3-7e93b9bbe46a');
