INSERT INTO learning_records (customer_id, initial_coaching_level, case_interview_progress, case_interview_weaknesses, id) VALUES (E'81f6ef0a-0dca-47da-9d35-e6c23e9e1eeb', E'トップ外資戦略は十分内定可能なポテンシャルがある', E'■読んだ書籍\n・ロジカルシンキングを超える戦略思考 フェルミ推定の技術 \n・「フェルミ推定」から始まる問題解決の技術 \n\n■使っている有料サービス\n・noteにおけるケースの有料記事\n\n■壁打ちの回数\n・1回のみ\n\n■内定実績\n・2021年に転職活動した際、Strategy&様に内定を頂きました（当時は辞退し、ドリームインキュベータに入社しました）', E'①ケース面接の勘の取り戻し\n過去のAccenture・ドリームインキュベータへの転職活動で、ケース面接の流れや対策は一通り理解しているつもりではありつつ、\n実際のケース面接からは数年遠ざかっているため、実践的な練習をし、ケースの勘を取り戻せればと考えています\n\n②ドリームインキュベータ アソシエイトマネージャーに期待されるケース面接の水準の把握\nコンサル経験者・かつ・現職でアソシエイトマネージャーのため、面接で要求水準も高いのでは？と推測しています\n上記状況で、ケース面接で求められる水準のご所感頂ければ大変に幸いです', E'facd5c57-795f-4b04-be49-31ed5b0c637a');
INSERT INTO learning_records (customer_id, initial_coaching_level, case_interview_progress, id) VALUES (E'597fe7a5-e7fd-4874-820b-1e39bdc6ae20', E'トップ外資戦略はチャレンジ、その他戦略なら十分内定可能なポテンシャルがある', E'戦略コンサルティングファームの面接試験　過去問で鍛える地頭力', E'b86eceae-f012-437f-8e56-0cb341c1db35');
INSERT INTO learning_records (customer_id, initial_coaching_level, case_interview_progress, case_interview_weaknesses, id) VALUES (E'0b5f0e77-bdb9-40ba-a967-a4dde6647706', E'その他戦略はチャレンジ、大手総合なら十分内定可能なポテンシャルがある', E'東大ケース本。イシューから始めよ。ロジカルプレゼンテーション。ロジカルシンキング', E'陳腐な施策の提案。ビジネス的な売り上げ向上系以外のケース問題に対して苦手意識。', E'b11246ee-2030-47c3-ba78-66bced2fe8a7');
INSERT INTO learning_records (customer_id, id) VALUES (E'546c1742-1f26-4562-8804-d1c04ad4836c', E'f4be3d2b-7391-412f-8000-c54075c15d6d');
