INSERT INTO learning_records (customer_id, mentor_name, coaching_start_date, coaching_end_date, last_coaching_date, contract_months, total_sessions, weekly_sessions, completed_sessions, level_fermi, level_case, level_up_range, interview_timing_at_end, target_companies_at_end, offer_probability_at_end, additional_coaching_proposal, initial_coaching_level, case_interview_progress, case_interview_weaknesses, mentoring_satisfaction, id) VALUES (E'8753a93a-9a32-46c7-af14-4e385292a4b2', E'明石', E'2025-07-08', E'2025-08-08', E'2025-08-03', 1, 6, 1.4, 8, E'上級者レベル：短時間かつほぼノーミスで立式、根拠づけ、計算ができる', E'中級者レベル：仮説を元にファーストアウトプットを考える姿勢があるが論理の破綻などの指摘を受ける/ディスカッションに不自然な点がある', E'全体的にスタート時は全くの初心者\n\nデリバリー\n・かなりよくなった。最初は結論が何かもよくわからない状態だったが、聞きやすい発表の仕方になった\n\nフェルミ推定\n・基本的な問題であれば中級者レベルで解ける\n\nケース\n・公共系はまだ弱いが、基本的な売上向上ケースであれば中級者レベルで解ける', E'未定', E'McK, BCG, Bain, Tier2戦コン, その他戦コン, 総コン', E'0.6', E'未案内のため本フォーム提出後に提案', E'トップ外資戦略はチャレンジ、その他戦略なら十分内定可能なポテンシャルがある', E'フェルミ推定、売上向上、論点設計といったケースを1種類ずつ解いた程度。', E'・売上向上をテーマとするケースでは、解き始めにどの軸で切り出し、どのように構造化するかで手が止まりがち。\n・筋道だった説明を終始保つことにも不安が残り、冒頭の前提確認では何を優先して押さえるべきか判断に迷うことがある。\n・発表後の追加質問への即応力にも課題を感じており、とくにオンライン面接では対面以上に緊張しやすい。', E'4.733333333', E'8c8d1d06-0242-466f-920b-c1acaa3dc3bf');
INSERT INTO learning_records (customer_id, mentor_name, coaching_start_date, coaching_end_date, last_coaching_date, contract_months, total_sessions, weekly_sessions, completed_sessions, level_case, level_up_range, interview_timing_at_end, target_companies_at_end, offer_probability_at_end, additional_coaching_proposal, initial_coaching_level, case_interview_progress, case_interview_weaknesses, id) VALUES (E'068a90a8-e1ca-4c10-9155-f08b7d4d652b', E'小島', E'2025-07-05', E'2025-09-05', E'2025-09-04', 2, 8, 0.9333333333, 9, E'上級者レベル：仮説を元に論理の破綻のないファーストアウトプットができ、ディスカッションでの深堀りにも対応できる', E'かなりレベルアップした。時間内に完成度の高いアウトプットを出せるようになった。デリバリーもかなりよくなった。', E'8,9月ごろ', E'BCG, Bain, Tier2戦コン, その他戦コン', E'0.6', E'提案済みだが消極的に検討中', E'トップ外資戦略は十分内定可能なポテンシャルがある', E'使用した書籍は考えるエンジン高松氏の書籍3冊、東大生シリーズなど、壁打ちは3回程度しており、第2志望群企業の面接が開始している状況です。', E'構造化して話す部分に改善余地があるという指摘を受けます', E'e9284754-e73b-4255-a62d-c08d873d0204');
