INSERT INTO learning_records (customer_id, initial_coaching_level, case_interview_progress, case_interview_weaknesses, id) VALUES (E'caf87ce1-3a6c-49d0-9ad0-13f0fb745963', E'ワンチャンコンサル受けない', E'ケース面接に関して\n┗記事を呼んだりしていますが対策はまだ特にできていないです。\n┗KPMGのケース面接を今週末受ける予定です。\n就活状況に関して\n┗5月半ばに就活を始め選考中の企業様が多いです。レバレジーズさんからは最終面接のご案内をいただきました。', E'具体⇒抽象化は苦手意識がないのですが、抽象⇒具体化はあまり得意ではないと思っております。\n汎用性のある思考のテンプレートやフローなどを習得したいです。', E'1807322b-7af5-4438-9460-eb7acf37de77');
