INSERT INTO learning_records (customer_id, initial_coaching_level, case_interview_progress, case_interview_weaknesses, id) VALUES (E'3ac48f0f-b0c3-49cd-b779-fea89f9969de', E'トップ外資戦略はチャレンジ、その他戦略なら十分内定可能なポテンシャルがある', E'戦略コンサルティングファームの面接試験、地頭を鍛えるフェルミ推定/ケース面接ノート、フェルミ推定の教科書', E'具体的な数字を設定すること、\nPEファンドのMA戦略のようなケース（ある程度のビジネス知識を要する実践的な内容）、\n公共ケース、\nグローバル規模のケース', E'0987caf8-9a7b-4e3f-8bb6-33871dd953ad');
INSERT INTO learning_records (customer_id, case_interview_progress, case_interview_weaknesses, id) VALUES (E'88db9f3c-dedc-436f-a372-a971478a8357', E'問題解決力を高める 外資系コンサルの入社試験、ロジカルシンキングを超える戦略思考 フェルミ推定の技術（これから読む）', E'クイックアンドダーティーでも立式ができない、計算の速さ', E'2905e4da-4803-4008-ac14-e55690d71247');
