INSERT INTO learning_records (customer_id, mentor_name, coaching_start_date, coaching_end_date, last_coaching_date, contract_months, total_sessions, weekly_sessions, completed_sessions, session_completion_rate, level_case, initial_coaching_level, case_interview_progress, case_interview_weaknesses, mentoring_satisfaction, id) VALUES (E'a24cec90-d90d-4a75-82a6-ad5aa2d22c63', E'橘', E'2025-06-20', E'2025-08-20', E'2025-07-13', 2, 8, 0.9333333333, 5, 0.625, E'上級者レベル：仮説を元に論理の破綻のないファーストアウトプットができ、ディスカッションでの深堀りにも対応できる', E'トップ外資戦略は十分内定可能なポテンシャルがある', E'・読んだ書籍：地頭を鍛えるフェルミ推定ノートなど数冊（5年以上前）\n・使っている有料サービス：昨年別の企業を受けていた際にはココナラを使いました\n・壁打ちの回数：今回の転職向けには0回\n・内定実績：（過去の転職時）BIG4 FASや戦コンには合格/内定をいただいた', E'【フェルミ】\n・短時間での抜け漏れのないフェルミの立式\n・計算、暗算力\n\n【ビジネスケース】\n・顧客ニーズを踏まえた打ち手の検討\n・打ち手の納得感・網羅感を与える説明方法', E'4', E'46a08da8-238b-4c26-9161-872dc8e78865');
