INSERT INTO learning_records (customer_id, case_interview_progress, case_interview_weaknesses, id) VALUES (E'e313c4b6-24fe-41db-ba08-afeb05b234c7', E'・本3冊：過去問で鍛える地頭力、東大生が書いたフェルミ推定、東大生が書いたケース面接\n・壁打ち2回：他転職エージェントで1度、ATカーニー社の勉強会で1度', E'・因数分解と計算に時間を取られる（因数が詳細すぎ＆数字の根拠を考えすぎ）\n・ボトルネック特定の後の策立案で理想は言えるが具体案として提案できない', E'f93affaa-6ce7-467c-956a-4be9878fc42b');
