INSERT INTO learning_records (customer_id, case_interview_progress, case_interview_weaknesses, id) VALUES (E'a60843d3-044d-469d-9408-415dfed4de7c', E'東大生のケース面接、フェルミ推定', E'フェルミ推定やケース面接の流れをまだ深く理解できていないです。', E'74d5ec63-d367-460b-8f9b-878247c7b629');
