INSERT INTO learning_records (customer_id, case_interview_progress, case_interview_weaknesses, id) VALUES (E'66e40a26-32cd-4a05-8942-5f567aa54ac4', E'書籍：東大生本(ケース、フェルミ)、過去問で鍛える地頭力\n壁打ち回数：1回(MBBの友人と)', E'施策がありきたりでしょぼいものしか思いつかない、時間内に回答できるか不安', E'b9c4b1f3-20bb-4868-bca6-f30eb7a96ba0');
INSERT INTO learning_records (customer_id, id) VALUES (E'3792f2c0-ff0e-4f1e-ab57-2248c264e851', E'1f804c07-f7ff-40ab-8c48-3077347dd239');
INSERT INTO learning_records (customer_id, case_interview_progress, case_interview_weaknesses, id) VALUES (E'c72132db-55bb-475d-bf07-91e57d66394c', E'過去問で鍛える地頭力　地頭鍛えるフェルミ推定ノート　ケース問題ノート', E'フェルミに関しては質問に対しアプローチ設定を需要ベースとするか供給ベースか迷い、決めてもとりあえずペンを動かして後付けで色々くっつけるので最終的な数字に自信が持てない。あとは数字の仮定に自信が持てない。たとえば東京都内にあるタクシーの総台数は何台か？という問いにアプローチ設定として東京のタクシー会社数×会社毎の平均所有台数とした場合、東京のタクシー会社をどうおき、会社毎の平均所有台数をどうおくか、背景知識で例えば主要タクシー会社は都内だと3社くらい、会社毎の平均所有台数は仮で1000としましょうなど、数字が感覚値であることに違和感あり。ケース面接で何を評価されているのかの解像度が上がればまたやり方も変わるのかもしれません。', E'3957948b-161c-4098-9868-65448411c2c9');
