INSERT INTO learning_records (customer_id, mentor_name, coaching_start_date, coaching_end_date, last_coaching_date, contract_months, total_sessions, weekly_sessions, completed_sessions, session_completion_rate, level_fermi, level_case, case_interview_progress, case_interview_weaknesses, mentoring_satisfaction, id) VALUES (E'bfbb3eee-5e5b-43e4-ba79-3ee4d128b775', E'亀井', E'2025-04-30', E'2025-05-30', E'2025-07-30', 1, 8, 1.866666667, 20, 2.5, E'初級者レベル：時間内に答えが出ない/式に大きな誤りがある/計算ミスが頻発する', E'中級者レベル：仮説を元にファーストアウトプットを考える姿勢があるが論理の破綻などの指摘を受ける/ディスカッションに不自然な点がある', E'地頭を鍛えるフェルミ推定ノート、ケース問題ノート、過去問で鍛える地頭力、戦略コンサルティングファームの面接試験を一読', E'話し方や短時間でのアウトプット等', E'4.857142857', E'34b05729-d583-415c-a2b9-7a9c83dacffb');
INSERT INTO learning_records (customer_id, last_coaching_date, case_interview_progress, case_interview_weaknesses, id) VALUES (E'c7eef9c2-64fb-4056-9bee-2ca7d4ae5f2e', E'2025-04-29', E'フェルミ推定の技術', E'フェルミでのセグメント分け、ケースでのフレームワークの知識不足、ケースでの網羅性の欠如、ケースでの深掘りの浅さ、ケースでの根拠の弱さ', E'd2eea412-eeda-4f79-8d01-91f6ffc418c4');
