INSERT INTO learning_records (customer_id, case_interview_progress, case_interview_weaknesses, id) VALUES (E'2b58a5bd-1dc4-4b42-871e-ab2d30b92d57', E'・読んだ書籍：東大生の書いたフェルミ推定ノート、東大生の書いたケース問題ノート、フェルミ推定の技術\n・壁打ち回数：3回程度\n・内定実績：ブティック系戦略ファーム内定有り、その他MBB選考通過中', E'１．思考を構造化する力\n２．スピード\n３．言語化', E'2dbf7cd8-22c1-4f9c-819e-5bffcdb748f4');
INSERT INTO learning_records (customer_id, contract_months, total_sessions, weekly_sessions, session_completion_rate, case_interview_progress, case_interview_weaknesses, mentoring_satisfaction, id) VALUES (E'77b1dda4-453a-458e-9f6e-cc77b37af50b', 1, 8, 1.866666667, 0.0, E'・読了書籍：\n　『東大生が書いた　フェルミ推定＋ケース面接』（通称：東大本）を一通り読み終えました\n\n・利用している有料サービス：\n　現在、有料サービスは利用しておりません\n\n・所属コミュニティ：\n　選抜コミュニティには未所属です\n\n・壁打ち経験：\n　エージェントと1回実施\n\n・内定実績：\n　まだ内定は獲得しておりません', E'・即時の深掘り・展開に弱い\n追加の問いかけに対し、別視点の提示や仮説の修正をその場で行うのが難しく、思考の瞬発性に課題がある。\n・アウトプット\n緊張により声が小さくなる、曖昧な表現になるといった傾向があり、自信のなさが表に出やすい。また、海外経験が長く、ビジネス日本語でのロジカルな表現や言い回しにも不安があるため、面接中の伝え方全般に課題を感じている。\n・計算ミスが多い\nフェルミ推定や試算時に、桁や単位のミスなどケアレスミスが出やすい。\n・準備方針が不明確\n新卒時にコンサル選考を受けていなかったこともあり、どう逆算して必要な準備をするのかがわからない', E'3.5', E'ac9bc84c-00be-421e-a6bc-7f8df3d6acc6');
INSERT INTO learning_records (customer_id, case_interview_weaknesses, id) VALUES (E'7957e248-9fff-4e4e-9d9f-02e45d263b8f', E'マッキンゼーの英語ケース面接にどう対策すべきか知らなかったです', E'3005e661-16bf-4059-8317-307fd72aff4a');
INSERT INTO learning_records (customer_id, case_interview_progress, case_interview_weaknesses, id) VALUES (E'9b72e925-04cc-443e-8186-54a58765e5ad', E'ほぼなし', E'（本格的なケース面接の対策を行ったことはないが）多業界のビジネス知見が足りていないこともあり、ディスカッションの土台となるファーストアウトプットの出力が遅い方であると自覚している。', E'659e8f02-2920-403d-840d-74c8d33d3559');
