INSERT INTO learning_records (customer_id, mentor_name, coaching_start_date, last_coaching_date, total_sessions, completed_sessions, session_completion_rate, progress_text, level_fermi, level_case, case_interview_progress, id) VALUES (E'e2b00e74-9dd4-4aac-8d0f-04b2111999ce', E'喜山', E'2025-05-02', E'2025-09-29', 10, 8, 0.8, E'順調', E'中級者レベル：基本動作を習得しているが、立式、根拠づけ、計算においてミスや指摘を受ける', E'上級者レベル：仮説を元に論理の破綻のないファーストアウトプットができ、ディスカッションでの深堀りにも対応できる', E'高松智史　ロジカルシンキングを超える戦略思考フェルミ推定の技術（背後の問題を30題程度解いた）\n東大ケーススタディ研究会　東大生が書いた問題を解く力を鍛えるケース問題ノート（前半９題を問いた）', E'2d05f5db-1123-4923-b7b8-8706975fd008');
INSERT INTO learning_records (customer_id, case_interview_progress, case_interview_weaknesses, id) VALUES (E'7a1c4a21-e21d-4c95-84cb-88b03115cc0e', E'・読んだ書籍：ロジカルシンキングを超える戦略思考 フェルミ推定の技術', E'・論点分解時の濃淡（後で考えたときに些末な論点を細かく砕いてしまう）\n・論点の検討漏れに後から気づいて時間が足りなくなる\n・イメージが難しいお題の際に思考が止まってしまう（例 ドローンの市場規模 等）', E'6004404c-4c92-481b-bb82-a0323f084679');
INSERT INTO learning_records (customer_id, mentor_name, coaching_start_date, coaching_end_date, last_coaching_date, contract_months, total_sessions, weekly_sessions, completed_sessions, session_completion_rate, case_interview_progress, case_interview_weaknesses, id) VALUES (E'af5c2e44-5a24-444b-8f05-1e8ea5558520', E'中森', E'2025-04-27', E'2025-08-27', E'2025-12-14', 4, 20, 1.166666667, 19, 0.95, E'JDSCの夏インターンとエッグフォーワード選考中という状況です。ケースの練習は、3月から始めました。選考の時期としては、秋冬を考えています。読んだ書籍につきましては、東大生ケース本、過去問で鍛える地頭力　戦略思考トレーニング1 等です。たまに、case match などの無料のサービスを使って、壁打ちしてます。\n選抜コミュニティ未所属です。', E'とにかく思考時間に間に合わない。問題によって、施策の良し悪しがある。', E'86a83789-b26d-43f3-946e-801da99306bf');
