INSERT INTO learning_records (customer_id, mentor_name, coaching_start_date, coaching_end_date, last_coaching_date, contract_months, total_sessions, weekly_sessions, completed_sessions, level_up_range, interview_timing_at_end, target_companies_at_end, offer_probability_at_end, additional_coaching_proposal, case_interview_progress, case_interview_weaknesses, mentoring_satisfaction, id) VALUES (E'612ac647-d5df-4842-8ec3-7fa04e084935', E'亀井', E'2025-04-16', E'2025-07-16', E'2025-12-23', 3, 12, 0.9333333333, 18, E'基本的な部分には改善がみられるが、まだ内定には届かない。', E'指導期間延長のため聞いていない', E'McK, BCG, Bain, Tier2戦コン, その他戦コン', E'0.6', E'既に追加指導を購入済み', E'・読んだ書籍:問題解決（高田 貴久）、ロジカル・プレゼンテーション（高田 貴久）\n・読んでいる書籍:ビジネスモデルの教科書（今枝 昌宏）\n・壁打ちの回数:1回', E'思考スピード、複雑に考えがち', E'4', E'a3656ef3-5896-4ff0-8ed7-4a825e55e40f');
