INSERT INTO learning_records (customer_id, mentor_name, coaching_start_date, coaching_end_date, last_coaching_date, contract_months, total_sessions, weekly_sessions, completed_sessions, level_fermi, level_case, level_up_range, interview_timing_at_end, target_companies_at_end, offer_probability_at_end, additional_coaching_proposal, extension_days, case_interview_progress, case_interview_weaknesses, mentoring_satisfaction, id) VALUES (E'ad849c8a-2c51-4964-bba6-fb7c3a7daeb9', E'亀井', E'2025-04-08', E'2025-05-10', E'2025-06-04', 1, 8, 1.866666667, 8, E'上級者レベル：短時間かつほぼノーミスで立式、根拠づけ、計算ができる', E'上級者レベル：仮説を元に論理の破綻のないファーストアウトプットができ、ディスカッションでの深堀りにも対応できる', E'もともとレベルは高かったが、十分内定可能なレベル感まで上がったと考えられる。', E'7月頭程度', E'BCG, Bain, Tier2戦コン', E'0.8', E'提案済みで前向きに検討中', 2, E'読んだ書籍：『過去問で鍛える地頭力』『フェルミ推定の技術』『「フェルミ推定」から始まる問題解決の技術』　※書籍インプットのみで、有料サービスやコミュニティの利用は現時点でなし。また、現職の就職時の選考ではケース面接はなかったため、新卒時も特段トレーニングはしていない。', E'インプット・アウトプットともに不足している自覚あり。特に、思考の結果を十分に整理して面接官にデリバリーできるか不安。', E'4', E'db9779b6-559a-4a62-bc89-8c73889a4fbb');
INSERT INTO learning_records (customer_id, mentor_name, coaching_start_date, coaching_end_date, last_coaching_date, contract_months, total_sessions, weekly_sessions, completed_sessions, session_completion_rate, level_case, case_interview_progress, case_interview_weaknesses, mentoring_satisfaction, id) VALUES (E'9ec32df8-cb5f-495f-a0cd-edc2b6de4357', E'西山', E'2025-05-12', E'2025-08-12', E'2025-07-15', 3, 12, 0.9333333333, 10, 0.8333333333, E'上級者レベル：仮説を元に論理の破綻のないファーストアウトプットができ、ディスカッションでの深堀りにも対応できる', E'[読んだ書籍]\n戦略コンサルティング・ファームの面接攻略法（ビクター・チェン）\n戦略コンサルティング・ファームの面接試験（マーク・コゼンティーノ）\n「フェルミ推定」から始まる問題解決の技術（高松智史）\n仮説思考（内田和成）\n現役東大生が書いた地頭を鍛えるフェルミ推定ノート\n現役東大生が書いた問題を解く力を鍛えるケース問題ノート\n地頭力を鍛える（細谷功）\n過去問で鍛える地頭力（大石哲之）\n\n[使っている有料サービス]\nココナラで現役コンサルタントの方に一度模擬面接をしてもらった。\n\n[壁打ちの回数]\n今年の2月後半に転職活動を開始。これまでの模擬/本番面接は以下3回。他に友人等との面接練習は無し。（他は本で勉強のみ）\n・\t3月前半：転職コンサルタントによる模擬面接\n・\t3月後半：ドリームインキュベータ一次面接（→落ちた）\n・\t4月前半：ココナラにて現役コンサルタントによる模擬面接\n\n[選考状況]\n3月末にドリームインキュベータとローランドベルガーの２社の選考プロセスにエントリー。ドリームインキュベータは一次面接で落ち、ローランドベルガーは書類審査を突破できず。', E'・\tケース面接のような短い時間（例：3分間）で自分の考えを纏めることに慣れておらず、時間内に適切なアウトプットを出せない＋焦って余計に考えが纏まらない。\n・\tフェルミ推定において主要な論点やセグメントを見落としてしまうことがある。\n・\tこれまでマーケティング業務の経験無し。そのためか、自分の導いたフェルミ推定の数値（例：市場規模）が妥当かどうか、セルフチェックが上手く出来ていない。', E'4', E'f33afb9a-3097-4101-b717-78b66df150be');
INSERT INTO learning_records (customer_id, progress_text, case_interview_progress, case_interview_weaknesses, id) VALUES (E'fe98e944-a8c7-4165-b7a7-a71b15cf9acd', E'順調', E'東大生シリーズ、元BCG高松さん著者の本、過去問で鍛える自頭力、戦略コンサルティングファームの面接攻略法など一通り。（新卒時も含む）昨年は英語のケースを15回程度練習、日本語はココナラで2－3回程度', E'他のアイデアや切り口を問われたときにすぐに考えが出ず、思考が止まってしまう。自信のなさが伝わってしまう。', E'83c58bcf-0f7e-40ae-a1f3-9611949bfa62');
INSERT INTO learning_records (customer_id, mentor_name, coaching_start_date, coaching_end_date, last_coaching_date, contract_months, total_sessions, weekly_sessions, completed_sessions, session_completion_rate, level_case, extension_days, case_interview_progress, case_interview_weaknesses, mentoring_satisfaction, id) VALUES (E'10189949-08ab-4ed6-85bc-a24f892232c5', E'亀井', E'2025-04-07', E'2025-10-06', E'2025-11-14', 4, 20, 1.166666667, 18, 0.9, E'初級者レベル：施策がアイデアベース/自分で考えられていない/仮説から考えられていない/構造化やロジックが甘い', 60, E'東大生が書いたシリーズ', E'最初の構造化', E'5', E'a903190e-e801-44f2-9028-3bd65a1fd8da');
